WHEN NOT MATCHED THEN INSERT (class_type_code,value_code,name_en,parent_value_id,tag,display_order,is_active,created_by)
  VALUES ('DCT_PROGRAM','P070705','ALC Promotion',(SELECT class_value_id FROM prod.dct_gl_class_value WHERE class_type_code='DCT_PROGRAM' AND value_code='P070700'),NULL,410,'Y','SEED')
WHEN MATCHED THEN UPDATE SET t.name_en='ALC Promotion',t.parent_value_id=(SELECT class_value_id FROM prod.dct_gl_class_value WHERE class_type_code='DCT_PROGRAM' AND value_code='P070700'),t.tag=NULL,t.display_order=410;

-- ---- clear prior seed mappings (re-runnable) ----
DELETE FROM prod.dct_gl_seg_class_map WHERE created_by='SEED';

