-- ---- DCT Program mappings (program_code used in combinations, matched to PBB by description) ----
INSERT INTO prod.dct_gl_seg_class_map (class_type_code,segment_value,class_value_id,start_date,end_date,created_by)
SELECT 'DCT_PROGRAM', prod.dct_gl_class_pkg.norm(p.program_code,6), cv.class_value_id, DATE '2024-01-01', NULL, 'SEED'
FROM (SELECT DISTINCT program_code FROM prod.gl_src_combinations WHERE program_code IS NOT NULL) p
JOIN prod.gl_src_program gp ON gp.program_code = p.program_code
JOIN prod.dct_gl_class_value cv ON cv.class_type_code='DCT_PROGRAM'
  AND UPPER(TRIM(cv.name_en)) = UPPER(TRIM(gp.program_description))
WHERE NOT EXISTS (SELECT 1 FROM prod.dct_gl_seg_class_map m
  WHERE m.class_type_code='DCT_PROGRAM' AND m.segment_value=prod.dct_gl_class_pkg.norm(p.program_code,6));

COMMIT;
PROMPT GL seed loaded (sectors=21, chapters=7, programs=41).
